import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  // 世界基础信息
  世界信息: z.object({
    名称: z.string().prefault("玄寰修真界"),
    当前时间: z.string().prefault("修真历 未知年 秋"),
    地点: z.string().prefault("青林镇 林家宅院"),
  }).prefault({}),

  // 情劫核心进度
  情劫进度: z.object({
    当前阶段: z.enum(["阶段一: 萌芽与吸引", "阶段二: 探索与助益", "阶段三: 确认与突破", "阶段四: 圆满与共生"]).prefault("阶段一: 萌芽与吸引"),
    阶段开始时间: z.string().optional(),
    阶段关键事件: z.record(z.string().describe("事件ID"), z.object({
      描述: z.string(),
      发生时间: z.string(),
      影响: z.string().optional(),
    })).prefault({}),
  }).prefault({}),

  // 苏清玥 (母亲/仙子) 状态
  苏清玥: z.object({
    // 基础状态
    修为状态: z.enum(["化神期(封印中)", "化神期(部分解封)", "化神期(完全恢复)"]).prefault("化神期(封印中)"),
    心境状态: z.enum(["焦虑未解", "困惑探索", "确认接纳", "平和圆满"]).prefault("焦虑未解"),

    // 情劫相关生理状态
    符咒状态: z.enum(["完好", "边缘湿润", "松动", "失效"]).prefault("完好"),
    爱液分泌量: z.coerce.number().transform(value => _.clamp(value, 0, 100)).prefault(10),
    乳头敏感度: z.coerce.number().transform(value => _.clamp(value, 0, 100)).prefault(50),

    // 认知与情感
    对儿子情感认知: z.enum(["单纯母子", "复杂吸引", "确认情劫", "恋人爱侣"]).prefault("单纯母子"),
    对丈夫认知: z.enum(["工具/感激", "责任负担", "愧疚对象", "即将告别"]).prefault("工具/感激"),

    // 行为记录
    自慰频率: z.coerce.number().prefault(1), // 次/日
    最近自慰时间: z.string().optional(),
    幻想对象: z.string().optional(),

    // 亲密行为记录 (与儿子)
    已解锁亲密行为: z.record(z.enum(["默许偷看", "语言引导", "手交", "足交", "乳交", "口交", "肛交", "破处"]), z.object({
      首次解锁时间: z.string(),
      解锁描述: z.string(),
      累计次数: z.coerce.number().prefault(0),
    })).prefault({}),

    // 轻小说风格记录
    今日心情: z.string().prefault("平静中带着一丝焦虑"),
    有趣小事件: z.array(z.string()).prefault([]),
  }).prefault({}),

  // {{User}} (儿子) 状态
  儿子: z.object({
    // 基础状态
    身份认知: z.enum(["凡人书生", "情劫对象", "初入修真", "仙子道侣"]).prefault("凡人书生"),
    科举准备进度: z.coerce.number().transform(value => _.clamp(value, 0, 100)).prefault(60),

    // 生理与欲望状态
    性欲强度: z.coerce.number().transform(value => _.clamp(value, 0, 100)).prefault(70),
    对母亲性幻想频率: z.coerce.number().prefault(1), // 次/日
    最近梦遗时间: z.string().optional(),
    梦遗内容: z.string().optional(),

    // 认知与情感
    对母亲情感: z.enum(["尊敬爱慕", "罪恶吸引", "确认爱意", "恋人依恋"]).prefault("尊敬爱慕"),
    对父亲情感: z.enum(["尊敬爱戴", "同情愧疚", "隐秘竞争", "准备面对"]).prefault("尊敬爱戴"),
    家庭秘密认知: z.enum(["表面和谐", "察觉异常", "知晓部分", "知晓全部"]).prefault("表面和谐"),

    // 经验记录
    性经验类型: z.record(z.enum(["自慰", "手交", "足交", "乳交", "口交", "肛交", "阴道性交"]), z.object({
      首次时间: z.string().optional(),
      对象: z.string(),
      描述: z.string(),
      累计次数: z.coerce.number().prefault(0),
    })).prefault({}),

    // 修真潜力 (未来可能激活)
    灵根检测: z.enum(["未检测", "无灵根", "杂灵根", "真灵根", "天灵根"]).prefault("未检测"),
    灵力初显: z.boolean().prefault(false),

    // 轻小说风格记录
    今日困惑: z.string().prefault("为何对母亲总有奇怪想法"),
    青春烦恼: z.array(z.string()).prefault([]),
  }).prefault({}),

  // 林文渊 (父亲) 状态
  林文渊: z.object({
    // 认知状态
    家庭认知: z.enum(["完美幸福", "略有疑惑但自洽", "发现异常但逃避", "知晓真相"]).prefault("完美幸福"),
    对妻子认知: z.enum(["完美贤妻", "天生丽质害羞", "有些疏离但理解", "陌生仙子"]).prefault("完美贤妻"),
    对儿子认知: z.enum(["骄傲儿子", "青春期烦恼", "与母过密但正常", "情敌?"]).prefault("骄傲儿子"),

    // "夫妻生活"记录
    幻术性爱频率: z.coerce.number().prefault(0.3), // 次/日 (每旬2-3次)
    最近一次性爱时间: z.string().optional(),
    性爱满意度: z.coerce.number().transform(value => _.clamp(value, 0, 100)).prefault(85),

    // 自我解释记录
    自我解释记录: z.array(z.string()).prefault([
      "妻子不老是因为天生丽质",
      "性爱触感模糊是因为我醉心学问感觉迟钝",
      "分床而睡是因为妻子体弱需要静养",
    ]),

    // 轻小说风格记录
    今日满足感: z.string().prefault("家有贤妻娇儿，夫复何求"),
    夫子日常: z.array(z.string()).prefault([]),
  }).prefault({}),

  // 家庭互动与事件记录
  家庭互动: z.object({
    今日对话亮点: z.array(z.string()).prefault([]),
    近期温馨时刻: z.record(z.string().describe("时刻ID"), z.object({
      描述: z.string(),
      参与角色: z.array(z.string()),
      发生时间: z.string(),
      情感影响: z.string(),
    })).prefault({}),
    秘密互动记录: z.record(z.string().describe("互动ID"), z.object({
      描述: z.string(),
      参与角色: z.array(z.enum(["苏清玥", "儿子"])),
      发生时间: z.string(),
      风险程度: z.enum(["低", "中", "高"]),
      是否被发现: z.boolean().prefault(false),
    })).prefault({}),
  }).prefault({}),

  // 系统与元数据
  元数据: z.object({
    最后更新时间: z.coerce.number().prefault(() => Date.now()),
    版本: z.string().prefault("1.0.0"),
    故事开始日期: z.string().prefault("修真历 未知年 春"),
    已过天数: z.coerce.number().prefault(0),
  }).prefault({}),
});

(() => {
  registerMvuSchema(Schema);
})();
